import{_ as o,o as a,c as d,ae as r}from"./chunks/framework.9V9r4W13.js";const P=JSON.parse('{"title":"环境变量与特殊标识","description":"","frontmatter":{},"headers":[],"relativePath":"server/runtime/environment.md","filePath":"server/runtime/environment.md","lastUpdated":1777818009000}'),t={name:"server/runtime/environment.md"};function i(l,e,c,n,_,s){return a(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="环境变量与特殊标识" tabindex="-1">环境变量与特殊标识 <a class="header-anchor" href="#环境变量与特殊标识" aria-label="Permalink to &quot;环境变量与特殊标识&quot;">​</a></h1><h2 id="运行环境" tabindex="-1">运行环境 <a class="header-anchor" href="#运行环境" aria-label="Permalink to &quot;运行环境&quot;">​</a></h2><h3 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h3><ol><li><code>PS_RUNTIME</code>,标记此时程序是通过<code>PS</code>专门的运行时启动的</li><li><code>PS_LOG_LEVEL</code> <code>info/log/warning/error</code> 对应0到3，只有高于<code>PS_LOG_LEVEL</code>的信息才会被输出</li><li><code>PS_STRICT</code> 如果设置，那么使用了未设置的守卫、管道等，会直接报错</li><li><code>PS_PURE</code> 如果设置，不会去检查守卫管道等</li><li><code>PS_GENERATE</code>只生成代码，不运行</li><li><code>PS_APP_NAME</code>应用名，在默认日志中显示</li></ol><h3 id="特殊标识" tabindex="-1">特殊标识 <a class="header-anchor" href="#特殊标识" aria-label="Permalink to &quot;特殊标识&quot;">​</a></h3><p><strong>PS_ERROR</strong>,标记是否被<code>filter</code>处理，即请求是否出错 <strong>PS_HMR</strong>，给热更新调用的回调 <code>PS_EXIT_CODE</code>,传给运行时的退出类型</p><h2 id="命令行-运行时" tabindex="-1">命令行/运行时 <a class="header-anchor" href="#命令行-运行时" aria-label="Permalink to &quot;命令行/运行时&quot;">​</a></h2><h3 id="环境变量-1" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量-1" aria-label="Permalink to &quot;环境变量&quot;">​</a></h3><ol><li><code>PS_BAN_CLI_LOG</code>设置了的话，禁止命令行的日志输出</li><li><code>PS_CONFIG_FILE</code> 配置文件的路径，默认为<code>ps.json</code></li><li><code>PS_DTS_PATH</code>类型文件的路径，默认为<code>ps.d.ts</code></li><li><code>PS_PORT_RELEASE_DELAY</code>为等待端口释放的时长，默认为50</li><li><code>PS_DISABLE_WATCH</code> 禁止监听文件变化，禁止运行时的热更新</li><li><code>PS_LOADER_PATH</code>，详见<code>examples/http/loader.js</code></li></ol><blockquote><p>因为暂时没有找到方法确认进程结束后端口是否释放，只好手动延时（如果没有用到服务端框架则无所谓）</p></blockquote>',10)])])}const S=o(t,[["render",i]]);export{P as __pageData,S as default};
